import{_ as a,o as n,c as t,ag as e}from"./chunks/framework.Bgwu_dgr.js";const g=JSON.parse('{"title":"스킬이란 무엇인가","description":"","frontmatter":{},"headers":[],"relativePath":"topics/what-are-skills.md","filePath":"topics/what-are-skills.md","lastUpdated":null}'),i={name:"topics/what-are-skills.md"};function l(p,s,o,r,c,d){return n(),t("div",null,[...s[0]||(s[0]=[e(`<h1 id="스킬이란-무엇인가" tabindex="-1">스킬이란 무엇인가 <a class="header-anchor" href="#스킬이란-무엇인가" aria-label="Permalink to &quot;스킬이란 무엇인가&quot;">​</a></h1><p>스킬의 정의를 물으면 Zhang과 Murag은 길고 기술적인 답을 내놓지 않는다. 그들의 대답은 거의 탈기술적이다.</p><blockquote><p>스킬은 에이전트가 사용하는 <strong>절차적 지식을 패키지로 묶은 파일 모음</strong>이다. 더 쉽게 말하자면 -- <strong>폴더다.</strong></p></blockquote><p>이 정의의 핵심은 &quot;폴더&quot;라는 단어가 담고 있는 <strong>익숙함과 이식성</strong>이다. 폴더는 새로운 것을 배울 필요가 없다. 어디에나 있다. Git으로 버전 관리할 수 있고, Google Drive에 올릴 수 있고, ZIP으로 묶어 이메일로 보낼 수 있다. 이 단순함은 실수가 아니라 <strong>설계 철학의 결과</strong>다.</p><h2 id="최소-단위-skill-md-파일-하나" tabindex="-1">최소 단위 -- <code>SKILL.md</code> 파일 하나 <a class="header-anchor" href="#최소-단위-skill-md-파일-하나" aria-label="Permalink to &quot;최소 단위 -- \`SKILL.md\` 파일 하나&quot;">​</a></h2><p>하나의 스킬은 최소한 <code>SKILL.md</code>라는 마크다운 파일 하나만 있으면 성립한다. 이 파일의 상단에는 YAML 프론트매터가 있다.</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">invoice-processing</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  사내 표준 양식의 송장을 읽고, 회계 시스템이 요구하는 형식으로</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  변환하여 검증하는 절차.</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span></code></pre></div><p>그 아래에는 실제 절차 지식이 마크다운으로 기록된다. &quot;이 스킬은 무엇을 하는가, 언제 사용되는가, 단계별로 무엇을 수행해야 하는가.&quot; 사내 위키 문서를 작성하는 감각과 크게 다르지 않다.</p><p><code>SKILL.md</code> 하나로도 충분히 작동하는 스킬이 가능하다는 점이 중요하다. 처음부터 거창한 엔지니어링 아티팩트를 만들 필요가 없다. <strong>문서 한 장에서 시작하고, 필요에 따라 자라게 한다</strong>는 설계가 민주화를 낳는다.</p><h2 id="확장되는-구조-스크립트-참조-바이너리" tabindex="-1">확장되는 구조 -- 스크립트, 참조, 바이너리 <a class="header-anchor" href="#확장되는-구조-스크립트-참조-바이너리" aria-label="Permalink to &quot;확장되는 구조 -- 스크립트, 참조, 바이너리&quot;">​</a></h2><p>하지만 스킬은 거기서 멈추지 않는다. 복잡한 문제에는 <strong>스크립트, 참조 문서, 실행 파일, 리소스</strong>가 필요하다. 스킬 폴더는 이것을 전부 담을 수 있는 컨테이너다.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>invoice-processing/</span></span>
<span class="line"><span>├── SKILL.md                    # 스킬의 진입점과 메타데이터</span></span>
<span class="line"><span>├── reference/</span></span>
<span class="line"><span>│   ├── field-mapping.md        # 필드 매핑 규칙</span></span>
<span class="line"><span>│   └── legacy-formats.md       # 구형 양식 처리 가이드</span></span>
<span class="line"><span>├── scripts/</span></span>
<span class="line"><span>│   ├── validate.py             # 검증 스크립트</span></span>
<span class="line"><span>│   └── convert.py              # 변환 스크립트</span></span>
<span class="line"><span>└── templates/</span></span>
<span class="line"><span>    └── corrected.tmpl.pdf      # 교정 템플릿</span></span></code></pre></div><p>에이전트는 <code>SKILL.md</code>를 먼저 읽고, 필요한 세부 사항이 있을 때에만 <code>reference/</code> 안의 문서를 열어본다. 변환이 필요하면 <code>scripts/convert.py</code>를 실행한다. 스킬이 제공하는 것은 **지식(문서), 능력(스크립트), 리소스(템플릿)**의 세 층이다.</p><h2 id="도구가-아닌-스크립트를-택한-이유" tabindex="-1">도구가 아닌 스크립트를 택한 이유 <a class="header-anchor" href="#도구가-아닌-스크립트를-택한-이유" aria-label="Permalink to &quot;도구가 아닌 스크립트를 택한 이유&quot;">​</a></h2><p>기존 에이전트 설계에서 많이 쓰인 방식은 <strong>도구(tool) 호출</strong>이었다. 에이전트에게 <code>calculate_tax(year, income)</code> 같은 함수 시그니처를 노출하고, 모델은 JSON 스키마로 파라미터를 채워 호출한다.</p><p>스킬은 이 방식을 사용하지 않는다. 대신 <strong>스크립트 파일</strong>을 폴더에 넣어두고, 에이전트가 필요할 때 그것을 직접 읽고 실행한다. Zhang과 Murag이 이 선택을 설명하는 논거는 세 가지다.</p><ol><li><strong>자기 문서화</strong> -- 스크립트 안의 변수명, 주석, 로직이 그 자체로 설명이다.</li><li><strong>수정 가능성</strong> -- 에이전트가 특정 케이스에 맞춰 스크립트를 <strong>그 자리에서 수정</strong>할 수 있다. 도구는 블랙박스라 이것이 불가능하다.</li><li><strong>런타임과의 자연스러운 통합</strong> -- 파일 시스템과 코드 실행 환경을 이미 가진 에이전트에게, 스크립트는 추가 추상화 없이 쓸 수 있는 제1 시민이다.</li></ol><h2 id="슬라이드-스타일링-사례-왜-스킬로-저장해야-하는가" tabindex="-1">슬라이드 스타일링 사례 -- 왜 스킬로 저장해야 하는가 <a class="header-anchor" href="#슬라이드-스타일링-사례-왜-스킬로-저장해야-하는가" aria-label="Permalink to &quot;슬라이드 스타일링 사례 -- 왜 스킬로 저장해야 하는가&quot;">​</a></h2><p>Zhang은 실제 Anthropic 내부에서 관찰된 장면 하나를 소개한다. 슬라이드를 만들 때마다 Claude는 거의 같은 Python 스크립트를 처음부터 다시 작성하고 있었다. 폰트, 색, 여백, 레이아웃 규칙을 매번 같은 논리로 재구성한 것이다.</p><p>이것을 <strong>스킬로 저장한 순간</strong>, 두 가지가 바뀌었다.</p><ul><li><strong>일관성</strong> -- 같은 작업의 결과물이 매번 똑같이 나온다.</li><li><strong>누적성</strong> -- 개선이 휘발되지 않는다. 스킬을 한 번 고치면 이후의 모든 실행에 반영된다.</li></ul><p>슬라이드 스타일링은 간단한 예지만, 같은 논리가 대규모 조직에서는 거대한 레버리지를 만든다. 사내 코드 스타일, 배포 체크리스트, 리포트 템플릿, 법무 리뷰 절차 -- 모두 같은 원리로 스킬이 된다.</p><h2 id="단순함은-의도된-설계다" tabindex="-1">단순함은 의도된 설계다 <a class="header-anchor" href="#단순함은-의도된-설계다" aria-label="Permalink to &quot;단순함은 의도된 설계다&quot;">​</a></h2><p>발표 내내 반복되는 어조는 &quot;스킬은 단순하다&quot;는 것이다. 왜 단순함을 이토록 강조할까? 답은 <strong>누가 만들 수 있는가</strong>와 연결된다.</p><ul><li>SDK가 필요하면 엔지니어만 만든다.</li><li>전용 IDE가 필요하면 학습 비용이 든다.</li><li>새 런타임이 필요하면 배포 비용이 든다.</li></ul><p>폴더와 마크다운. 이 두 가지만으로 충분하게 설계된 이유는, <strong>법무, 재무, 회계, 리크루팅 담당자</strong>가 자신의 전문성을 직접 에이전트에게 가르칠 수 있어야 하기 때문이다. 이것이 단순히 개발자 편의의 문제가 아니라 <strong>민주화의 조건</strong>이라는 점이 이 장의 핵심이다.</p><blockquote><p>누구나, 인간이든 에이전트든, 만들고 쓸 수 있어야 한다.</p></blockquote><p>스킬의 단순함은 결국 이 목표를 위한 <strong>거부할 수 없는 제약</strong>이었다.</p>`,28)])])}const k=a(i,[["render",l]]);export{g as __pageData,k as default};
